pc.script.createLoadingScreen(function (app) {
    var showSplash = function () {
        var wrapper = document.createElement('div');
        wrapper.id = 'application-splash-wrapper';
        document.body.appendChild(wrapper);

        var gameImg = document.createElement('div');
        gameImg.id = 'application-game-image';
        wrapper.appendChild(gameImg);

        var gameLogo = document.createElement('div');
        gameLogo.id = 'application-game-logo';
        wrapper.appendChild(gameLogo);

        var container = document.createElement('div');
        container.id = 'progress-bar-container';
        wrapper.appendChild(container);

        var bar = document.createElement('div');
        bar.id = 'progress-bar';
        container.appendChild(bar);

        var starsContainer = document.createElement('div');
        starsContainer.id = 'stars-container';
        wrapper.appendChild(starsContainer);

        let appCanvas = document.getElementById('application-canvas');
        if (appCanvas) {
            appCanvas.style.zIndex = -1;
        }

        const numStars = 12;
        const colors = ['#EA74F5', '#8774F5', '#B974F5', '#74CCF5', ' #74F5CC', '#ff99cc', '#ff80b3', '#ff66a3',];

        function createCandySVG(size, color = "#590062", fillColor = color, options = {}) {
            const svgNS = "http://www.w3.org/2000/svg";
            const svg = document.createElementNS(svgNS, "svg");

            // Set up SVG dimensions and viewBox to match the original
            svg.setAttribute("width", size);
            svg.setAttribute("height", size);
            svg.setAttribute("viewBox", "0 0 34 34");
            svg.setAttribute("fill", "none");

            // Create the main candy paths with white fill
            const candyPath1 = document.createElementNS(svgNS, "path");
            candyPath1.setAttribute("d", "M12.0355 25.1617L10.6024 30.8904C10.4829 31.3685 10.2387 31.8064 9.8947 32.1593C9.55069 32.5121 9.11919 32.7674 8.64427 32.8989C8.16935 33.0305 7.66802 33.0337 7.19147 32.9081C6.71492 32.7826 6.28023 32.5328 5.93179 32.1843L1.81626 28.0706C1.49425 27.7488 1.25604 27.353 1.1225 26.9178C0.988963 26.4826 0.964159 26.0213 1.05026 25.5743C1.13637 25.1273 1.33076 24.7082 1.6164 24.3538C1.90205 23.9993 2.27024 23.7203 2.68874 23.5411L8.09629 21.2244");
            candyPath1.setAttribute("fill", "white");
            candyPath1.setAttribute("class", "colorChange");
            svg.appendChild(candyPath1);

            const candyPath2 = document.createElementNS(svgNS, "path");
            candyPath2.setAttribute("d", "M8.09606 15.9728L15.9726 8.09629C16.6688 7.40027 17.613 7.00926 18.5974 7.00926C19.5819 7.00926 20.5261 7.40027 21.2223 8.09629L26.4739 13.3498C27.17 14.046 27.561 14.9902 27.561 15.9746C27.561 16.9591 27.17 17.9033 26.4739 18.5995L18.5974 26.476C17.9012 27.172 16.957 27.563 15.9726 27.563C14.9881 27.563 14.0439 27.172 13.3477 26.476L8.09606 21.2207C7.40004 20.5245 7.00903 19.5803 7.00903 18.5958C7.00903 17.6113 7.40004 16.6672 8.09606 15.9709V15.9728ZM25.1615 12.0355L30.8902 10.6024C31.3683 10.4829 31.8062 10.2387 32.159 9.8947C32.5119 9.55069 32.7671 9.11919 32.8987 8.64427C33.0303 8.16935 33.0334 7.66801 32.9079 7.19147C32.7823 6.71492 32.5326 6.28023 32.1841 5.93179L28.0704 1.81626C27.7486 1.49425 27.3528 1.25604 26.9176 1.1225C26.4824 0.988963 26.0211 0.964159 25.5741 1.05026C25.1271 1.13637 24.708 1.33076 24.3535 1.6164C23.9991 1.90205 23.72 2.27024 23.5409 2.68874L21.2223 8.09629");
            candyPath2.setAttribute("fill", "white");
            candyPath2.setAttribute("class", "colorChange");
            svg.appendChild(candyPath2);

            // Create the main outline stroke
            const outlinePath = document.createElementNS(svgNS, "path");
            outlinePath.setAttribute("d", "M12.0355 25.1617L10.6024 30.8904C10.4829 31.3685 10.2387 31.8064 9.8947 32.1593C9.55069 32.5121 9.11919 32.7674 8.64427 32.8989C8.16935 33.0305 7.66802 33.0337 7.19147 32.9081C6.71492 32.7826 6.28023 32.5328 5.93179 32.1843L1.81626 28.0706C1.49425 27.7488 1.25604 27.353 1.1225 26.9178C0.988963 26.4826 0.964159 26.0213 1.05026 25.5743C1.13637 25.1273 1.33076 24.7082 1.6164 24.3538C1.90205 23.9993 2.27024 23.7203 2.68874 23.5411L8.09629 21.2244M21.2223 8.09629C20.5261 7.40027 19.5819 7.00926 18.5974 7.00926C17.613 7.00926 16.6688 7.40027 15.9726 8.09629L8.09606 15.9728V15.9709C7.40004 16.6672 7.00903 17.6113 7.00903 18.5958C7.00903 19.5803 7.40004 20.5245 8.09606 21.2207L13.3477 26.476C14.0439 27.172 14.9881 27.563 15.9726 27.563C16.957 27.563 17.9012 27.172 18.5974 26.476L26.4739 18.5995C27.17 17.9033 27.561 16.9591 27.561 15.9746C27.561 14.9902 27.17 14.046 26.4739 13.3498L21.2223 8.09629ZM21.2223 8.09629L23.5409 2.68874C23.72 2.27024 23.9991 1.90205 24.3535 1.6164C24.708 1.33076 25.1271 1.13637 25.5741 1.05026C26.0211 0.964159 26.4824 0.988963 26.9176 1.1225C27.3528 1.25604 27.7486 1.49425 28.0704 1.81626L32.1841 5.93179C32.5326 6.28023 32.7823 6.71492 32.9079 7.19147C33.0334 7.66801 33.0303 8.16935 32.8987 8.64427C32.7671 9.11919 32.5119 9.55069 32.159 9.8947C31.8062 10.2387 31.3683 10.4829 30.8902 10.6024L25.1615 12.0355");
            outlinePath.setAttribute("stroke", color);
            outlinePath.setAttribute("stroke-width", "2");
            outlinePath.setAttribute("stroke-linecap", "round");
            outlinePath.setAttribute("stroke-linejoin", "round");
            svg.appendChild(outlinePath);

            // Create the diagonal lines
            const line1 = document.createElementNS(svgNS, "line");
            line1.setAttribute("x1", "14.7071");
            line1.setAttribute("y1", "9.29289");
            line1.setAttribute("x2", "24.7071");
            line1.setAttribute("y2", "19.2929");
            line1.setAttribute("stroke", color);
            line1.setAttribute("stroke-width", "2");
            svg.appendChild(line1);

            const line2 = document.createElementNS(svgNS, "line");
            line2.setAttribute("x1", "9.70711");
            line2.setAttribute("y1", "15.2929");
            line2.setAttribute("x2", "19.7071");
            line2.setAttribute("y2", "25.2929");
            line2.setAttribute("stroke", color);
            line2.setAttribute("stroke-width", "2");
            svg.appendChild(line2);

            // Create the filled overlay areas
            const overlay1 = document.createElementNS(svgNS, "path");
            overlay1.setAttribute("d", "M15.0371 9.43713L16.3 8.11942C17.4464 6.92322 19.3455 6.88286 20.5417 8.02927L26.3662 13.6114C27.5624 14.7578 27.6027 16.6569 26.4563 17.8531L25.1934 19.1708L15.0371 9.43713Z");
            overlay1.setAttribute("fill", fillColor);
            overlay1.setAttribute("fill-opacity", "0.29");
            svg.appendChild(overlay1);

            const overlay2 = document.createElementNS(svgNS, "path");
            overlay2.setAttribute("d", "M19.3845 24.9084L18.099 26.204C16.932 27.3802 15.0325 27.3876 13.8564 26.2206L8.12962 20.5382C6.9535 19.3712 6.94611 17.4717 8.11312 16.2956L9.39868 15L19.3845 24.9084Z");
            overlay2.setAttribute("fill", fillColor);
            overlay2.setAttribute("fill-opacity", "0.29");
            svg.appendChild(overlay2);

            return svg;
        }

        for (let i = 0; i < numStars; i++) {
            const star = document.createElement('div');
            star.classList.add('star');
            const size = 50;
            const starSVG = createCandySVG(size, "#590062");
            star.appendChild(starSVG);

            // Add click event listener to change color
            star.addEventListener('click', function () {
                const randomColor = colors[Math.floor(Math.random() * colors.length)];
                const svgPaths = this.querySelectorAll(".colorChange");
                svgPaths[0].style.fill = randomColor;
                svgPaths[1].style.fill = randomColor;
                this.style.filter = `drop-shadow(0 0 15px ${randomColor})`;
            });

            // Apply fixed keyframe animation
            star.style.animation = `star-path-${i} ${12 + i}s infinite ease-in-out, twinkle ${3 + i % 3}s infinite alternate`;

            starsContainer.appendChild(star);
        }

    };

    var hideSplash = function () {
        let appCanvas = document.getElementById('application-canvas');
        if (appCanvas) {
            appCanvas.style.removeProperty('z-index');
        }

        var splash = document.getElementById('application-splash-wrapper');
        if (splash) {
            splash.parentElement.removeChild(splash);
        }

        document.body.style.backgroundColor = '#ffc8de';
    };

    var setProgress = function (value) {
        var bar = document.getElementById('progress-bar');
        if (bar) {
            value = Math.min(1, Math.max(0, value));
            bar.style.width = value * 100 + '%';
        }
    };



    var createCss = function () {
        var css = [
            'body, html {',
            '    height: 100%;',
            '   background: linear-gradient(330deg, #FF8E90 20.87%, #FFC383 86.9%);',
            '   background-size: 100% 100%;',
            '   height: 100vh;',
            '}',
            '@keyframes pulse{',
            '   from {transform: scale(0.9);}',
            '   to {transform: scale(1);}',
            '}',
            '#application-splash-wrapper {',
            '    display: flex;',
            '    flex-direction: column;',
            '    height: 90vh;',
            '    justify-content: center;',
            '    align-items: center;',
            '}',
            '#application-game-image {',
            '    animation: pulse 2s infinite ease-in-out alternate;',
            '    z-index: 1;',
            '    pointer-events: none;',
            '    width: 80vw;',
            '    height: 50vh;',
            '    max-width: 540px;',
            '    max-height: 540px;',
            '    background-size: contain;',
            '    background-position: center;',
            '    background-repeat: no-repeat;',
            '    background-image: url("data:image/png;base64,");',
            '}',
            '#application-game-logo {',
            '    animation: wiggle 2s ease-in-out .5s infinite;',
            '    z-index: 3;',
            '    pointer-events: none;',
            '    width: 80vw;',
            '    height: 30vh;',
            '    max-width: 540px;',
            '    max-height: 210px;',
            '    background-size: contain;',
            '    background-position: center;',
            '    background-repeat: no-repeat;',
            '    background-image: url("data:image/png;base64,");',
            '}',

            '@keyframes wiggle {',
            '  0% { transform: rotate(0); }',
            '  10% {transform: rotate(-5deg) scale(1.05);}',
            '  20% {transform: rotate(3deg) scale(1.07);}',
            '  30% {transform: rotate(-2deg) scale(1.03);}',
            '  35% {transform: rotate(0) scale(1);}',
            '}',


            '#progress-bar-container {',
            '    position:fixed;',
            '    pointer-events: none;',
            '    bottom:8px;',
            '    left:1%;',
            '    width:98%;',
            '    z-index:2;',
            '    border-radius: 11px;',
            '    margin: 20px auto 0 auto;',
            '    height: 10%;',
            '    max-height: 40px;',
            '    background-color: #AA006F;',
            '}',
            '',
            '#progress-bar {',
            '    width: 0%;',
            '    height: 100%;',
            '    z-index:2;',
            '    border-radius: 10px;',
            '    background-color: #FFA8E7;',
            '}',
            '.stars-container {',
            '  position: absolute;',
            '  width: 100vw;',
            '  height: 100vh;',
            '  top: 0;',
            '  left: 0;',
            '}',
            '.star {',
            '  position: absolute;',
            '  cursor: pointer;',
            '  width: 0;',
            '  height: 0;',
            '  top: 50%;',
            '  left: 50%;',
            '  filter: drop-shadow(0 0 10px rgba(255, 255, 255, 0.7));',
            '}',
            '',
            '.star-shape {',
            '  fill: #ffffff;',
            '  transition: fill 0.3s;',
            '}',
            '#stars-container > :nth-child(1){',
            '  top:50%;',
            '  left:60%;',
            '}',
            '#stars-container > :nth-child(2){',
            '  top:40%;',
            '  left:60%;',
            '}',
            '#stars-container > :nth-child(3){',
            '  top:30%;',
            '  left:50%;',
            '}',
            '#stars-container > :nth-child(4){',
            '  top:33%;',
            '  left:30%;',
            '}',
            '#stars-container > :nth-child(5){',
            '  top:50%;',
            '  left:30%;',
            '}',
            '#stars-container > :nth-child(6){',
            '  top:70%;',
            '  left:30%;',
            '}',
            '#stars-container > :nth-child(7){',
            '  top:55%;',
            '  left:50%;',
            '}',
            '#stars-container > :nth-child(8){',
            '  top:70%;',
            '  left:60%;',
            '}',
            '#stars-container > :nth-child(9){',
            '  top:60%;',
            '  left:60%;',
            '}',


            '@keyframes star-path-0 {',
            '  0%, 100% { transform: translate(-70%, -50%) rotate(0deg); }',
            '  50% { transform: translate(calc(-70% + 30vw), calc(-50%)) rotate(180deg); }',
            '}',

            '@keyframes star-path-1 {',
            '  0%, 100% { transform: translate(-50%, -50%) rotate(0deg); }',
            '  50% { transform: translate(calc(-50% + 15vw), calc(-50% - 15vw)) rotate(180deg); }',
            '}',

            '@keyframes star-path-2 {',
            '  0%, 100% { transform: translate(-50%, -50%) rotate(0deg); }',
            '  50% { transform: translate(calc(-50%), calc(-50% - 20vw)) rotate(180deg); }',
            '}',

            '@keyframes star-path-3 {',
            '  0%, 100% { transform: translate(-50%, -50%) rotate(0deg); }',
            '  50% { transform: translate(calc(-50% - 15vw), calc(-50% - 15vw)) rotate(180deg); }',
            '}',

            '@keyframes star-path-4 {',
            '  0%, 100% { transform: translate(-50%, -50%) rotate(0deg); }',
            '  50% { transform: translate(calc(-50% - 20vw), calc(-50%)) rotate(180deg); }',
            '}',

            '@keyframes star-path-5 {',
            '  0%, 100% { transform: translate(-50%, -50%) rotate(0deg); }',
            '  50% { transform: translate(calc(-50% - 15vw), calc(-50% + 15vw)) rotate(180deg); }',
            '}',

            '@keyframes star-path-6 {',
            '  0%, 100% { transform: translate(-50%, -50%) rotate(0deg); }',
            '  50% { transform: translate(calc(-50%), calc(-50% + 20vw)) rotate(180deg); }',
            '}',

            '@keyframes star-path-7 {',
            '  0%, 100% { transform: translate(-50%, -50%) rotate(0deg); }',
            '  50% { transform: translate(calc(-50% + 15vw), calc(-50% + 40vh)) rotate(180deg); }',
            '}',

            '@keyframes star-path-8 {',
            '  0%, 100% { transform: translate(-50%, -50%) rotate(0deg); }',
            '  50% { transform: translate(calc(-50% + 30vw), calc(-50% + 8vh)) rotate(180deg); }',
            '}',

            '@keyframes star-path-9 {',
            '  0%, 100% { transform: translate(-50%, -50%) rotate(0deg); }',
            '  50% { transform: translate(calc(-50% + 20vw), calc(-50% + 18vh)) rotate(180deg); }',
            '}',

            '@keyframes twinkle {',
            '  0%, 100% { opacity: 0.7; }',
            '  50% { opacity: 1; }',
            '}',
        ].join('\n');

        var style = document.createElement('style');
        style.type = 'text/css';
        if (style.styleSheet) {
            style.styleSheet.cssText = css;
        } else {
            style.appendChild(document.createTextNode(css));
        }

        document.head.appendChild(style);
    };

    createCss();
    showSplash();

    app.on('preload:end', function () {
        app.off('preload:progress');
    });
    app.on('preload:progress', setProgress);
    app.on('poki:ready', hideSplash);
});